import React from 'react';

const Skills = () => (
  <section
    id="Skills"
    className="min-h-screen flex flex-col items-center py-24"
    style={{ background: '#0a192f', fontFamily: "'Orbitron', sans-serif" }}
  >
    <h1 className="text-4xl text-white mb-12 font-bold">Skills</h1>

    <div className="max-w-2xl w-full">
      <div
        className="p-6 rounded-xl"
        style={{ background: '#f8f9fa', borderLeft: '5px solid #0d6efd' }}
      >
        <p style={{ color: '#0b1f3a' }}>React, JS, CSS</p>
      </div>
    </div>
  </section>
);

export default Skills;
